(function(){$(()=>{$(document).on("submit",'[data-bb-toggle="import-available-data"]',async a=>{a.preventDefault();const t=$(a.currentTarget),e=t.find("select").val();if(!e||e.length===0){Botble.showError(t.data("empty-selection-message"));return}for(const r of e){const n=r===e[e.length-1];try{const o=new FormData;o.append("country_code",r),o.append("continue",n?0:1);const{error:c,data:s}=await $httpClient.make().withButtonLoading(t.find("button[type=submit]")).post(t.prop("action"),o);if(c){Botble.showError(s.message);return}n&&(Botble.showSuccess(s.message),t.find("select").val("").trigger("change"))}catch(o){Botble.showError(o.message)}}})})})();
